function esMayorDeEdad(edad) {
  return edad >= 18;
}

console.log(esMayorDeEdad(20)); // true
console.log(esMayorDeEdad(15)); // false

if (esMayorDeEdad(20)) {
  console.log('Puede entrar');
}

function areaRectangulo(base, altura) {
  return base * altura;
}

const sala = areaRectangulo(5, 4);    // 20
const cocina = areaRectangulo(3, 3);  // 9
const total = sala + cocina;
console.log('Área total: ' + total + ' m²'); // 29 m²

